"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[77270],{70107:(e,l,n)=>{n.r(l),n.d(l,{data:()=>d});const d={key:"v-dacfb228",path:"/hexo/hexo%E6%96%87%E4%BB%B6%E5%8F%82%E6%95%B0%E5%8F%8A%E5%85%B6%E7%9B%B8%E5%85%B3%E8%AF%B4%E6%98%8E.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"1. _config.yml",slug:"_1-config-yml",children:[]},{level:2,title:"2. package.json",slug:"_2-package-json",children:[]},{level:2,title:"3. scaffolds",slug:"_3-scaffolds",children:[]},{level:2,title:"4. source",slug:"_4-source",children:[]},{level:2,title:"5. themes",slug:"_5-themes",children:[]},{level:2,title:"6. 关于文件名",slug:"_6-关于文件名",children:[]},{level:2,title:"7. 关于模板",slug:"_7-关于模板",children:[]},{level:2,title:"8. 关于Front-matter",slug:"_8-关于front-matter",children:[]},{level:2,title:"9. 关于分类和标签",slug:"_9-关于分类和标签",children:[]},{level:2,title:"10. 关于.json和.yml配置文件的区别",slug:"_10-关于-json和-yml配置文件的区别",children:[]},{level:2,title:"11. 关于文章内部的标签引用",slug:"_11-关于文章内部的标签引用",children:[]},{level:2,title:"12. 关于Asset资源文件夹",slug:"_12-关于asset资源文件夹",children:[]},{level:2,title:"13. 关于图片的显示",slug:"_13-关于图片的显示",children:[]},{level:2,title:"14. 关于Permalinks永久链接",slug:"_14-关于permalinks永久链接",children:[]},{level:2,title:"15. 关于多语种",slug:"_15-关于多语种",children:[]},{level:2,title:"16. 关于Themes主题设置",slug:"_16-关于themes主题设置",children:[]}],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"hexo/hexo文件参数及其相关说明.md"}},65036:(e,l,n)=>{n.r(l),n.d(l,{default:()=>ce});var d=n(57293);const i=(0,d._)("h2",{id:"_1-config-yml",tabindex:"-1"},[(0,d._)("a",{class:"header-anchor",href:"#_1-config-yml","aria-hidden":"true"},"#"),(0,d.Uk)(" 1. _config.yml")],-1),o=(0,d._)("p",null,[(0,d._)("em",null,"注意：这里面的东西不一定都要设置的，如果全部设置也是完全可以的，甚至你没必要在这个_config.yml设置，你可以自定义多个")],-1),a=(0,d.uE)("<strong>SITE</strong><code>title</code> 网站标题 <code>subtitle</code> 网站副标题 <code>description</code> 网站描述,告诉搜索引擎站点的简单描述 <code>keywords</code> 关键字,便于搜索引擎的搜索 <code>author</code> 作者名字，用于显示文章的作者 <code>language</code> 网站使用的语言,默认是英语，可设置的语言见",13),s={href:"https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes",target:"_blank",rel:"noopener noreferrer"},t=(0,d.Uk)("语言列表"),r=(0,d._)("code",null,"timezone",-1),c=(0,d.Uk)(" 网站时区，Hexo 默认使用电脑的时区，可设置的时区见"),u={href:"https://en.wikipedia.org/wiki/List_of_tz_database_time_zones",target:"_blank",rel:"noopener noreferrer"},m=(0,d.Uk)("时区列表"),h=(0,d.uE)("<p><strong>URL</strong><code>url</code> 网址 <code>root</code> 网站根目录 <code>permalink</code> 文章的永久链接格式 <code>permalink_defaults</code> 设置永久链接中各部分的默认值</p><p><strong>DIRECTORY</strong><code>source_dir</code> 资源文件夹，这个文件夹用来存放内容，默认是source <code>public_dir</code> 公共文件夹，这个文件夹用于存放生成的站点文件，默认是public <code>tag_dir</code> 标签文件夹，默认是tags <code>archive_dir</code> 归档文件夹，默认是archives <code>category_dir</code> 分类文件夹，默认是categories <code>code_dir</code> Include code 文件夹，默认是downloads/code <code>i18n_dir</code> 国际化（i18n）文件夹，默认是lang <code>skip_render</code> 跳过指定文件的渲染。比如source/mypage/hello.md 将会输出为index.html，而source/mypage/code.js不会渲染它，更多请移步我的其他文章</p>",2),v=(0,d.uE)("<strong>WRITING</strong><code>new_post_name</code> 新文章的文件名称格式 <code>:title.md</code>或者<code>:year-:month-:day-:title.md</code><code>default_layout</code> 预设布局,默认是post <code>auto_spacing</code> 在中文和英文之间加入空格，默认是false <code>titlecase</code> 把标题转换为title case,默认是false <code>external_link</code> 在新标签中打开链接,默认是true <code>filename_case</code> 把文件名称转换为小写(1)或大写(2),默认是0不转换 <code>render_drafts</code> 显示草稿，默认是false <code>post_asset_folder</code> 启动资源文件夹，默认是 false，表示source文件夹中除了文章以外的所有文件，例如图片、CSS、JS 文件等。比方说，如果你的Hexo项目中只有少量图片，那最简单的方法就是将它们放在source/images 文件夹中。 <code>relative_link</code> 把链接改为与根目录的相对位址，默认是false，默认情况下，Hexo生成的超链接都是绝对地址。例如，如果你的网站域名为",22),g={href:"http://example.com/",target:"_blank",rel:"noopener noreferrer"},p=(0,d.Uk)("example.com"),b=(0,d.Uk)(",您有一篇文章名为hello，那么绝对链接可能像这样：http://example.com/hello.html，它是绝对于域名的。相对链接像这样：/hello.html，也就是说，无论用什么域名访问该站点,一般建议用绝对路径 "),_=(0,d._)("code",null,"future",-1),x=(0,d.Uk)(" 显示未来的文章，默认是true "),f=(0,d._)("code",null,"highlight",-1),k=(0,d.Uk)(" 代码块的设置 "),y=(0,d._)("code",null,"enable: true",-1),q=(0,d.Uk)(" 启动高亮 "),E=(0,d._)("code",null,"line_number: true",-1),w=(0,d.Uk)(" 显示行号 "),U=(0,d._)("code",null,"auto_detect: false",-1),I=(0,d.Uk)(" 自动检查 "),D=(0,d._)("code",null,"tab_replace:",-1),W=(0,d.Uk)(" 缩进大小"),H=(0,d.uE)("<p><strong>HOME PAGE SETTING</strong><code>path</code> 博客默认页面的路径，默认为空 <code>per_page</code> 主页中每页显示的贴子，0表示禁止分页 <code>order_by</code> 按时间倒序排列</p><p><strong>CATEGORY &amp; TAG</strong><code>default_category</code> 默认分类，默认为没有分类uncategorized <code>category_map</code> 分类别名，默认为空 <code>tag_map</code> 标签别名，默认为空</p>",2),T=(0,d._)("strong",null,"DATE / TIME FORMAT",-1),j=(0,d._)("code",null,"date_format",-1),S=(0,d.Uk)(" 日期格式 YYYY-MM-DD "),A=(0,d._)("code",null,"time_format",-1),F=(0,d.Uk)(" 时间格式 H:mm:ss 按照"),L={href:"http://momentjs.com/docs/#/displaying/format/",target:"_blank",rel:"noopener noreferrer"},N=(0,d.Uk)("格式列表"),O=(0,d.Uk)("设置格式"),G=(0,d._)("p",null,[(0,d._)("strong",null,"PAGINATION"),(0,d._)("code",null,"per_page"),(0,d.Uk)(" 每页显示的文章量（0表示关闭分页），默认是10 "),(0,d._)("code",null,"pagination_dir"),(0,d.Uk)(" 分页目录，默认是page")],-1),B=(0,d._)("strong",null,"EXTENSIONS",-1),R=(0,d._)("code",null,"plugins",-1),C=(0,d.Uk)(" 插件，"),M={href:"https://hexo.io/plugins/",target:"_blank",rel:"noopener noreferrer"},Y=(0,d.Uk)("插件列表"),z=(0,d._)("code",null,"theme",-1),P=(0,d.Uk)(" 当前主题名称,为false时禁用主题,"),J={href:"https://hexo.io/themes/",target:"_blank",rel:"noopener noreferrer"},X=(0,d.Uk)("主题列表"),Z=(0,d._)("code",null,"theme_config",-1),K=(0,d.Uk)(" 自定义主题配置，这和全局的_config.yml文件是分离的，你可以写themes/my-theme/_config.yml，如果全局的_config.yml文件是 "),Q=(0,d._)("code",null,"theme_config:",-1),V=(0,d._)("code",null,'bio: "hello_world"',-1),$=(0,d.uE)('<p>而在你的<code>themes/my-theme/_config.yml</code>是 <code>bio: &quot;HELLO_WORLD&quot;</code><code>logo: &quot;hi.png&quot;</code> 那么结果是 <code>bio: &quot;hello_world&quot;</code><code>logo: &quot;hi.png&quot;</code> 也就是说如果在<code>themes/my-theme/_config.yml</code>中修改了全局<code>_config.yml</code>中的定义的参数，那么是无效的，但是可以添加全局<code>_config.yml</code>中没有的参数，如这里的logo</p><p><strong>DEPLOYMENT</strong><code>deploy:</code> 部署格式如下 <code>type: git</code><code>repository: https://github.com/xxx/xxx.github.io.git</code><code>branch: master</code></p><p><strong>INCLUDE/EXCLUDE FILES OR FOLDERS</strong> 设置键值使hexo显式或忽略某些文件 <code>include</code><code>-Impo</code> 包含Impo这个文件，include参数一般不使用，需要包含的文件hexo都做好了 <code>exclude</code><code>-.Igno</code> 忽略.Igno这个文件</p><p><strong>USING AN ALTERNATE CONFIG</strong> 自定义配置文件，使用<code>hexo server</code>启动时是默认加载_config.yml里面的配置，如果我们自定义文件custom.yml，那么启动时使用<code>hexo server --config custom.yml</code>,甚至是多个自定义文件custom1.yml,custom2.json,启动时使用<code>hexo server --config custom1.yml,custom2.json</code>，注意默认后面文件的优先级高，也就是先加载.json，多个自定义文件可以写入<code>_multiconfig.yml</code>中，同样最后一个文件优先加载</p><hr><h2 id="_2-package-json" tabindex="-1"><a class="header-anchor" href="#_2-package-json" aria-hidden="true">#</a> 2. package.json</h2><p>这是一些应用程序的信息，json格式，建议不要改动</p><hr><h2 id="_3-scaffolds" tabindex="-1"><a class="header-anchor" href="#_3-scaffolds" aria-hidden="true">#</a> 3. scaffolds</h2><p>这是一个模板文件夹，当你新写了一片文章时，其显示格式都会以scaffolds中post.md的内容来加载。</p><hr><h2 id="_4-source" tabindex="-1"><a class="header-anchor" href="#_4-source" aria-hidden="true">#</a> 4. source</h2><p>这是一个资源文件夹。以_开头的文件都会被忽略，.md和.html文件会被解析并放到public，其他文件也会被拷贝过去 (如果文件可以被渲染的话，会经过解析然后储存到 public 文件夹，否则会直接拷贝到 public 文件夹)</p><hr><h2 id="_5-themes" tabindex="-1"><a class="header-anchor" href="#_5-themes" aria-hidden="true">#</a> 5. themes</h2><p>主题文件夹，这部分请移步到其他文章。</p><hr><h2 id="_6-关于文件名" tabindex="-1"><a class="header-anchor" href="#_6-关于文件名" aria-hidden="true">#</a> 6. 关于文件名</h2><p>Hexo 默认以标题做为文件名称，编辑 new_post_name 参数来改变默认的文件名称,提供以下参数</p><blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>:title    标题（小写，空格将会被替换为短杠）\n:year 建立的年份，比如， 2015\n:month    建立的月份（有前导零），比如， 04\n:i_month  建立的月份（无前导零），比如， 4\n:day  建立的日期（有前导零），比如， 07\n:i_day    建立的日期（无前导零），比如， 7\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><hr><h2 id="_7-关于模板" tabindex="-1"><a class="header-anchor" href="#_7-关于模板" aria-hidden="true">#</a> 7. 关于模板</h2><p>在新建文章时，Hexo 会根据 scaffolds 文件夹内相对应的文件来建立文件，例如：<code>hexo new photo &quot;My Gallery&quot;</code>，在执行这行指令时，Hexo 会尝试在 scaffolds 文件夹中寻找 photo.md模板，并根据其内容建立文章，默认使用 _config.yml 中的 default_layout 参数post代替，模板文件中的参数有</p><blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>layout    布局\ntitle 标题\ndate  文件建立日期\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><hr><h2 id="_8-关于front-matter" tabindex="-1"><a class="header-anchor" href="#_8-关于front-matter" aria-hidden="true">#</a> 8. 关于Front-matter</h2><p>Front-matter 是文件最上方以 — 分隔的区域，用于指定个别文件的变量，举例来说：</p><blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>title: Hello World\ndate: 2013/7/13 20:46:25\n---\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><p>以下是预先定义的参数，在模板中使用这些参数值并加以利用。</p><blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>参数           描述                   默认值\nlayout       布局   \ntitle        标题\ndate         建立日期              文件建立日期\nupdated      更新日期              文件更新日期\ncomments     开启文章的评论功能     true\ntags         标签（不适用于分页）\ncategories   分类（不适用于分页）\npermalink    覆盖文章网址\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><hr><h2 id="_9-关于分类和标签" tabindex="-1"><a class="header-anchor" href="#_9-关于分类和标签" aria-hidden="true">#</a> 9. 关于分类和标签</h2><blockquote><p>只有文章支持分类和标签，您可以在 Front-matter 中设置。在其他系统中，分类和标签听起来很接近，但是在 Hexo 中两者有着明显的差别：分类具有顺序性和层次性，也就是说 Foo, Bar 不等于 Bar, Foo；而标签没有顺序和层次</p></blockquote><p>示例</p><blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>categories:\n- Diary\ntags:\n- PS3\n- Games\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><p><strong>注意</strong> 下面的方法会使分类Life成为Diary的子分类，而不是并列分类</p><blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>categories:\n- Diary\n- Life\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><hr><h2 id="_10-关于-json和-yml配置文件的区别" tabindex="-1"><a class="header-anchor" href="#_10-关于-json和-yml配置文件的区别" aria-hidden="true">#</a> 10. 关于.json和.yml配置文件的区别</h2><p>两者都可以来编写front-matter,只要将<code>---</code>换成<code>;;;</code>即可 例如</p><blockquote><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>&quot;title&quot;: &quot;Hello World&quot;,\n&quot;date&quot;: &quot;2013/7/13 20:46:25&quot;\n;;;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><hr><h2 id="_11-关于文章内部的标签引用" tabindex="-1"><a class="header-anchor" href="#_11-关于文章内部的标签引用" aria-hidden="true">#</a> 11. 关于文章内部的标签引用</h2><p>1，引用块 格式</p><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>{% blockquote [author[, source]] [link] [source_link_title] %}\n    content\n    {% endblockquote %}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>示例1</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>{% blockquote @DevDocs https://twitter.com/devdocs/status/356095192085962752 %}\n&gt;     NEW: DevDocs now comes with syntax highlighting. http://devdocs.io\n&gt;     {% endblockquote %}\n\n输出\n\nNEW: DevDocs now comes with syntax highlighting. http://devdocs.io\n\n@DevDocst--witter.com/devdocs/status/356095192085962752\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>示例2</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>{% blockquote Seth Godin http://sethgodin.typepad.com/seths_blog/2009/07/welcome-to-island-marketing.html Welcome to Island Marketing %}\n&gt;     Every interaction is both precious and an opportunity to delight.\n&gt;     {% endblockquote %}\n\n输出\n\nEvery interaction is both precious and an opportunity to delight.\n\nSeth GodinWelcome to Island Marketing\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>注意：对应关系</strong></p><p>2，代码块</p><p>示例1</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>{% codeblock %}\n&gt;     alert(&#39;Hello World!&#39;);\n&gt;     {% endcodeblock %}\n\n输出\n\nalert(&#39;Hello World!&#39;);\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>3，在文章中插入指定大小的图片。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>![[width] [height] [title text [alt text]]](http://localhost:4000/path/to/image)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><hr><h2 id="_12-关于asset资源文件夹" tabindex="-1"><a class="header-anchor" href="#_12-关于asset资源文件夹" aria-hidden="true">#</a> 12. 关于Asset资源文件夹</h2><p>资源（Asset）代表 source 文件夹中除了文章以外的所有文件，例如图片、CSS、JS 文件等。比方说，如果你的Hexo项目中只有少量图片，那最简单的方法就是将它们放在 source/images 文件夹中。然后通过类似于 <code>[图片上传失败...(image-22899b-1541302947970)]</code> 的方法访问它们。 当资源文件管理功能打开后(<code>post_asset_folder: true</code>)，Hexo将会在你每一次通过 <code>hexo new [layout] </code>命令创建新文章时自动创建一个文件夹。这个资源文件夹将会有与这个 markdown 文件一样的名字。将所有与你的文章有关的资源放在这个关联文件夹中之后，你可以通过相对路径来引用它们，这样你就得到了一个更简单而且方便得多的工作流。</p><hr><h2 id="_13-关于图片的显示" tabindex="-1"><a class="header-anchor" href="#_13-关于图片的显示" aria-hidden="true">#</a> 13. 关于图片的显示</h2><p>当你打开文章资源文件夹功能后，你把一个 example.jpg 图片放在了你的资源文件夹中，如果通过使用相对路径的常规 markdown 语法 <code>[图片上传失败...(image-9a9526-1541302947971)]</code> ，它将 不会 出现在首页上。（但是它会在文章中按你期待的方式工作） 正确的引用图片方式是使用下列的标签插件而不是 markdown ：``通过这种方式，图片将会同时出现在文章和主页以及归档页中。</p><hr><h2 id="_14-关于permalinks永久链接" tabindex="-1"><a class="header-anchor" href="#_14-关于permalinks永久链接" aria-hidden="true">#</a> 14. 关于Permalinks永久链接</h2><p>在 _config.yml 配置中调整网站的永久链接或者在每篇文章的 Front-matter 中指定。 除了下列变量外，您还可使用 Front-matter 中的所有属性。</p><blockquote><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>变量            描述\n:year          文章的发表年份（4 位数）\n:month         文章的发表月份（2 位数）\n:i_month       文章的发表月份（去掉开头的零）\n:day           文章的发表日期 (2 位数)\n:i_day         文章的发表日期（去掉开头的零）\n:title         文件名称\n:post_title    文章标题\n:id            文章 ID\n:category      分类。如果文章没有分类，则是 default_category 配置信息。permalink_defaults 参数调整永久链接中各变量的默认值：\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote>',65),ee=(0,d.Uk)("示例 假设 source/_posts 文件夹中有个 "),le={href:"http://hello-world.md/",target:"_blank",rel:"noopener noreferrer"},ne=(0,d.Uk)("hello-world.md"),de=(0,d.Uk)("，包含以下内容："),ie=(0,d.uE)('<blockquote><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>title: Hello World\ndate: 2013-07-14 17:01:34\ncategories:\n- foo\n- bar\n参数                             结果\n:year/:month/:day/:title/       2013/07/14/hello-world\n:year-:month-:day-:title.html   2013-07-14-hello-world.html\n:category/:title                foo/bar/hello-world\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><hr><h2 id="_15-关于多语种" tabindex="-1"><a class="header-anchor" href="#_15-关于多语种" aria-hidden="true">#</a> 15. 关于多语种</h2><p>修改 new_post_name 和 permalink 参数，如下：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>new_post_name: :lang/:title.md\npermalink: :lang/:title/\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>建立文章时，文章会被储存到：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>hexo new &quot;Hello World&quot; --lang en\n# =source/_posts/en/Hello-World.md\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>而网址会是： <code>http://localhost:4000/en/hello-world/</code></p><hr><h2 id="_16-关于themes主题设置" tabindex="-1"><a class="header-anchor" href="#_16-关于themes主题设置" aria-hidden="true">#</a> 16. 关于Themes主题设置</h2>',10),oe=(0,d.Uk)("在 themes 文件夹内，下载"),ae={href:"https://hexo.io/themes/",target:"_blank",rel:"noopener noreferrer"},se=(0,d.Uk)("主题"),te=(0,d.Uk)("，并修改 _config.yml 内的 theme 设定，即可切换主题。"),re={},ce=(0,n(63243).Z)(re,[["render",function(e,l){const n=(0,d.up)("ExternalLinkIcon");return(0,d.wg)(),(0,d.iD)(d.HY,null,[i,o,(0,d._)("p",null,[a,(0,d._)("a",s,[t,(0,d.Wm)(n)]),r,c,(0,d._)("a",u,[m,(0,d.Wm)(n)])]),h,(0,d._)("p",null,[v,(0,d._)("a",g,[p,(0,d.Wm)(n)]),b,_,x,f,k,y,q,E,w,U,I,D,W]),H,(0,d._)("p",null,[T,j,S,A,F,(0,d._)("a",L,[N,(0,d.Wm)(n)]),O]),G,(0,d._)("p",null,[B,R,C,(0,d._)("a",M,[Y,(0,d.Wm)(n)]),z,P,(0,d._)("a",J,[X,(0,d.Wm)(n)]),Z,K,Q,V]),$,(0,d._)("p",null,[ee,(0,d._)("a",le,[ne,(0,d.Wm)(n)]),de]),ie,(0,d._)("p",null,[oe,(0,d._)("a",ae,[se,(0,d.Wm)(n)]),te])],64)}]])},63243:(e,l)=>{l.Z=(e,l)=>{const n=e.__vccOpts||e;for(const[e,d]of l)n[e]=d;return n}}}]);